1	interface Item {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	}
6	
7	interface Policy {
8	  items: Item[];
9	  customer: { yearsWithMHPCO: number };
10	  isFollowUp: boolean;
11	}
12	
13	interface Incident {
14	  damages: { type: string; amount: number }[];
15	}
16	
17	const PROCESSING_FEE = 5;
18	const FIRST_INSURANCE_RATE = 0.1;
19	const BASE_PREMIUM: Record<string, number> = { sword: 100, staff: 80, potion: 40, rune: 25, moonstone: 25 };
20	const DEFAULT_BASE_PREMIUM = 60;
21	
22	const CURSE_SURCHARGE_RATE = 0.5;
23	const HIGH_ENCHANTMENT_THRESHOLD = 5;
24	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
25	const LOYALTY_THRESHOLD = 2;
26	const LOYALTY_DISCOUNT_RATE = 0.2;
27	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
28	const BLOCK_SIZE = 3;
29	const BLOCK_PREMIUM = 60;
30	
31	function basePremiumForType(type: string): number {
32	  return BASE_PREMIUM[type] ?? DEFAULT_BASE_PREMIUM;
33	}
34	
35	function itemSurcharges(item: Item): number {
36	  const base = basePremiumForType(item.type);
37	  let surcharge = 0;
38	  if (item.cursed) {
39	    surcharge += base * CURSE_SURCHARGE_RATE;
40	  }
41	  if (item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
42	    surcharge += base * HIGH_ENCHANTMENT_SURCHARGE_RATE;
43	  }
44	  return surcharge;
45	}
46	
47	function countByType(items: Item[]): Record<string, number> {
48	  const counts: Record<string, number> = {};
49	  for (const item of items) {
50	    counts[item.type] = (counts[item.type] ?? 0) + 1;
51	  }
52	  return counts;
53	}
54	
55	function itemGroupPremium(type: string, count: number): number {
56	  if (count === BLOCK_SIZE) {
57	    return BLOCK_PREMIUM;
58	  }
59	  return count * basePremiumForType(type);
60	}
61	
62	export function quote(policy: Policy) {
63	  const counts = countByType(policy.items);
64	
65	  let basePremium = 0;
66	  for (const [type, count] of Object.entries(counts)) {
67	    basePremium += itemGroupPremium(type, count);
68	  }
69	
70	  let totalItemSurcharges = 0;
71	  for (const item of policy.items) {
72	    totalItemSurcharges += itemSurcharges(item);
73	  }
74	
75	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
76	  const isLoyalCustomer = policy.customer.yearsWithMHPCO >= LOYALTY_THRESHOLD;
77	  const loyaltyDiscount = isLoyalCustomer ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
78	  const followUpDiscount = policy.isFollowUp ? basePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
79	  const totalPolicyDiscounts = loyaltyDiscount + followUpDiscount;
80	  const premium = Math.ceil(basePremium + totalItemSurcharges + firstInsuranceSurcharge - totalPolicyDiscounts + PROCESSING_FEE);
81	  return { premium };
82	}
83	
84	const INSURANCE_VALUE: Record<string, number> = { sword: 1000, rune: 250 };
85	const DEDUCTIBLE = 100;
86	
87	export function claim(policy: Policy, incident: Incident) {
88	  let insuranceSum = 0;
89	  for (const item of policy.items) {
90	    insuranceSum += INSURANCE_VALUE[item.type] ?? 0;
91	  }
92	  const totalCap = 2 * insuranceSum;
93	
94	  const HIGH_ENCH_CLAIM_THRESHOLD = 8;
95	  const HIGH_ENCH_REIMBURSEMENT_RATE = 0.5;
96	
97	  let payout = 0;
98	  for (const damage of incident.damages) {
99	    const policyItem = policy.items.find(item => item.type === damage.type);
100	    const enchantment = policyItem?.enchantment ?? 0;
101	    const reimbursement = enchantment >= HIGH_ENCH_CLAIM_THRESHOLD
102	      ? damage.amount * HIGH_ENCH_REIMBURSEMENT_RATE
103	      : damage.amount;
104	    payout += reimbursement - DEDUCTIBLE;
105	  }
106	
107	  const remainingCap = totalCap - payout;
108	  return { payout, remainingCap };
109	}
