1	interface Item {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	}
6	
7	interface Policy {
8	  items: Item[];
9	  customer: { yearsWithMHPCO: number };
10	  isFollowUp: boolean;
11	}
12	
13	interface Incident {
14	  damages: { type: string; amount: number }[];
15	}
16	
17	const PROCESSING_FEE = 5;
18	const FIRST_INSURANCE_RATE = 0.1;
19	const BASE_PREMIUM: Record<string, number> = { sword: 100, staff: 80, potion: 40, rune: 25, moonstone: 25 };
20	const DEFAULT_BASE_PREMIUM = 60;
21	
22	const CURSE_SURCHARGE_RATE = 0.5;
23	const HIGH_ENCHANTMENT_THRESHOLD = 5;
24	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
25	const LOYALTY_THRESHOLD = 2;
26	const LOYALTY_DISCOUNT_RATE = 0.2;
27	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
28	const BLOCK_SIZE = 3;
29	const BLOCK_PREMIUM = 60;
30	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
31	const HIGH_ENCHANTMENT_CLAIM_REIMBURSEMENT_RATE = 0.5;
32	
33	function basePremiumForType(type: string): number {
34	  return BASE_PREMIUM[type] ?? DEFAULT_BASE_PREMIUM;
35	}
36	
37	function itemSurcharges(item: Item): number {
38	  const base = basePremiumForType(item.type);
39	  let surcharge = 0;
40	  if (item.cursed) {
41	    surcharge += base * CURSE_SURCHARGE_RATE;
42	  }
43	  if (item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD) {
44	    surcharge += base * HIGH_ENCHANTMENT_SURCHARGE_RATE;
45	  }
46	  return surcharge;
47	}
48	
49	function countByType(items: Item[]): Record<string, number> {
50	  const counts: Record<string, number> = {};
51	  for (const item of items) {
52	    counts[item.type] = (counts[item.type] ?? 0) + 1;
53	  }
54	  return counts;
55	}
56	
57	function itemGroupPremium(type: string, count: number): number {
58	  if (count === BLOCK_SIZE) {
59	    return BLOCK_PREMIUM;
60	  }
61	  return count * basePremiumForType(type);
62	}
63	
64	export function quote(policy: Policy) {
65	  const counts = countByType(policy.items);
66	
67	  let basePremium = 0;
68	  for (const [type, count] of Object.entries(counts)) {
69	    basePremium += itemGroupPremium(type, count);
70	  }
71	
72	  let totalItemSurcharges = 0;
73	  for (const item of policy.items) {
74	    totalItemSurcharges += itemSurcharges(item);
75	  }
76	
77	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
78	  const isLoyalCustomer = policy.customer.yearsWithMHPCO >= LOYALTY_THRESHOLD;
79	  const loyaltyDiscount = isLoyalCustomer ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
80	  const followUpDiscount = policy.isFollowUp ? basePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
81	  const totalPolicyDiscounts = loyaltyDiscount + followUpDiscount;
82	  const premium = Math.ceil(basePremium + totalItemSurcharges + firstInsuranceSurcharge - totalPolicyDiscounts + PROCESSING_FEE);
83	  return { premium };
84	}
85	
86	const INSURANCE_VALUE: Record<string, number> = { sword: 1000, rune: 250 };
87	const DEDUCTIBLE = 100;
88	
89	export function claim(policy: Policy, incident: Incident) {
90	  let insuranceSum = 0;
91	  for (const item of policy.items) {
92	    insuranceSum += INSURANCE_VALUE[item.type] ?? 0;
93	  }
94	  const totalCap = 2 * insuranceSum;
95	
96	  let payout = 0;
97	  for (const damage of incident.damages) {
98	    const policyItem = policy.items.find(item => item.type === damage.type);
99	    const enchantment = policyItem?.enchantment ?? 0;
100	    const reimbursement = enchantment >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD
101	      ? damage.amount * HIGH_ENCHANTMENT_CLAIM_REIMBURSEMENT_RATE
102	      : damage.amount;
103	    payout += reimbursement - DEDUCTIBLE;
104	  }
105	
106	  const remainingCap = totalCap - payout;
107	  return { payout, remainingCap };
108	}
